package com.kalyani.car_rental_backend.notification.entity;
import com.kalyani.car_rental_backend.user.entity.User;import jakarta.persistence.*;import java.time.LocalDateTime;
@Entity @Table(name="notifications")
public class Notification{@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@ManyToOne(optional=false,fetch=FetchType.LAZY)private User user;@Column(nullable=false)private String title;@Column(nullable=false,length=1000)private String message;@Column(nullable=false)private String type="INFO";@Column(nullable=false)private boolean readFlag;@Column(nullable=false,updatable=false)private LocalDateTime createdAt;@PrePersist void pre(){createdAt=LocalDateTime.now();}
public Long getId(){return id;}public User getUser(){return user;}public void setUser(User v){user=v;}public String getTitle(){return title;}public void setTitle(String v){title=v;}public String getMessage(){return message;}public void setMessage(String v){message=v;}public String getType(){return type;}public void setType(String v){type=v;}public boolean isReadFlag(){return readFlag;}public void setReadFlag(boolean v){readFlag=v;}public LocalDateTime getCreatedAt(){return createdAt;}}
